public static String canonical(String path) {
    if (path == null || path.length() == 0) {
        return path;
    }

    int end = path.length();
    int start = path.lastIndexOf('/', end);

    search:
    while (end > 0) {
        switch (end - start) {
            case 2: // possible single dot
                if (path.charAt(start + 1) != '.') {
                    break;
                }
                break search;
            case 3: // possible double dot
                if (path.charAt(start + 1) != '.' || path.charAt(start + 2) != '.') {
                    break;
                }
                break search;
        }

        end = start;
        start = path.lastIndexOf('/', end - 1);
    }

    // If we have checked the entire string
    if (start >= end) {
        return path;
    }

    StringBuilder buf = new StringBuilder(path);
    int delStart = -1;
    int delEnd = -1;
    int skip = 0;

    while (end > 0) {
        switch (end - start) {
            case 2: // possible single dot
                if (buf.charAt(start + 1) != '.') {
                    if (skip > 0 && --skip == 0) {
                        delStart = start >= 0 ? start : 0;
                        if (delStart > 0 && delEnd == buf.length() && buf.charAt(delEnd - 1) == '.') {
                            delStart++;
                        }
                    }
                    break;
                }

                if (start < 0 && buf.length() > 2 && buf.charAt(1) == '/' && buf.charAt(2) == '/') {
                    break;
                }

                if (delEnd < 0) {
                    delEnd = end;
                }
                delStart = start;
                if (delStart < 0 || delStart == 0 && buf.charAt(delStart) == '/') {
                    delStart++;
                    if (delEnd < buf.length() && buf.charAt(delEnd) == '/') {
                        delEnd++;
                    }
                    break;
                }
                if (end == buf.length()) {
                    delStart++;
                }

                end = start--;
                while (start >= 0 && buf.charAt(start) != '/') {
                    start--;
                }
                continue;

            case 3: // possible double dot
                if (buf.charAt(start + 1) != '.' || buf.charAt(start + 2) != '.') {
                    if (skip > 0 && --skip == 0) {
                        delStart = start >= 0 ? start : 0;
                        if (delStart > 0 && delEnd == buf.length() && buf.charAt(delEnd - 1) == '.') {
                            delStart++;
                        }
                    }
                    break;
                }

                delStart = start;
                if (delEnd < 0) {
                    delEnd = end;
                }

                skip++;
                end = start--;
                while (start >= 0 && buf.charAt(start) != '/') {
                    start--;
                }
                continue;

            default:
                if (skip > 0 && --skip == 0) {
                    delStart = start >= 0 ? start : 0;
                    if (delEnd == buf.length() && buf.charAt(delEnd - 1) == '.') {
                        delStart++;
                    }
                }
        }

        // Do the delete
        if (skip <= 0 && delStart >= 0 && delEnd >= delStart) {
            buf.delete(delStart, delEnd);
            delStart = delEnd = -1;
        }

        end = start--;
        while (start >= 0 && buf.charAt(start) != '/') {
            start--;
        }
    }

    // Too many ..
    if (skip > 0) {
        return null;
    }

    // Do the delete
    if (delEnd >= 0) {
        buf.delete(delStart, delEnd);
    }

    return buf.toString();
}

